INSERT IGNORE INTO `dimension` (`id`, `name`, `description`, `sort_order`, `enabled`) VALUES
(1, '基础核查', '主体信息、资质及基本合规要素', 10, 1),
(2, '法务风险', '违约责任、解除权、争议解决', 20, 1),
(3, '财务风险', '付款、发票、税务、结算及费用承担', 30, 1),
(4, '形式核查', '签章、附件、文本格式和材料完整性', 40, 1),
(5, '一致性检查', '知识产权、数据权属及条款一致性', 50, 0);
INSERT IGNORE INTO `audit_point` (`id`, `dim_id`, `name`, `description`, `instruction`, `risk_points`, `examples`, `default_result`, `enabled`, `sort_order`) VALUES
(1, 1, '主体信息与签署授权', '核查甲乙方名称、统一社会信用代码、法定代表人与授权是否完整一致', '', '[{"name":"主体信息缺失","highStd":"主体信息或授权材料缺失将导致责任主体难以确认。","lowStd":"主体信息表述不完整，建议补充核对。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"主体信息或签署授权不完整，可能影响合同效力与追责。","suggestion":"补充双方主体信息、统一社会信用代码、法定代表人和授权文件。"}', 1, 10),
(2, 1, '标的范围与服务边界', '标的、服务范围与交付物边界是否清晰', '', '[{"name":"服务边界不清","highStd":"标的范围不清会导致验收和责任边界争议。","lowStd":"服务范围需进一步细化交付物。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"标的范围和服务边界不明确，容易引发履约争议。","suggestion":"明确服务范围、交付物清单、验收标准和排除事项。"}', 1, 20),
(3, 3, '价格、发票与付款条件', '价格、付款节点、比例与发票约定是否对我方不利', '', '[{"name":"付款条件风险","highStd":"付款节点或发票约定缺失可能造成资金和税务风险。","lowStd":"付款比例和开票时点需要细化。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"价格、付款和发票约定不清，可能造成回款或税务处理风险。","suggestion":"明确付款节点、支付时限、发票类型、税率和逾期责任。"}', 1, 30),
(4, 2, '交付计划与验收机制', '识别默示验收等对我方不利的验收条款', '', '[{"name":"默示验收风险","highStd":"默示验收可能导致质量问题被默认接受。","lowStd":"验收程序和标准需进一步明确。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"交付计划和验收机制不明确，可能导致自动验收或整改争议。","suggestion":"约定书面验收、明确验收标准、整改期限和复验流程。"}', 1, 40),
(5, 2, '质量保证与售后服务', '质保期、响应时限与售后责任是否明确', '', '[{"name":"售后保障不足","highStd":"质保责任和响应时限缺失会削弱履约保障。","lowStd":"售后服务标准需细化。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"质量保证和售后服务标准不够明确。","suggestion":"补充质保期、响应时限、服务等级和违约责任。"}', 1, 50),
(6, 2, '知识产权与成果归属', '成果、数据与衍生知识产权归属是否清晰', '', '[{"name":"权属不清","highStd":"成果和数据归属不清可能导致后续使用受限。","lowStd":"授权范围和使用边界需细化。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"知识产权和成果归属表述笼统，后续授权、使用和商业化可能产生争议。","suggestion":"明确成果、数据、衍生成果的权属和许可范围。"}', 1, 60),
(7, 2, '数据安全与保密义务', '数据安全、保密范围与期限是否完备', '', '[{"name":"保密义务缺失","highStd":"保密范围和数据安全义务缺失可能造成合规风险。","lowStd":"保密期限和例外需要完善。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"数据安全和保密义务不完整，可能导致敏感信息保护不足。","suggestion":"补充保密范围、期限、例外、数据安全措施和违约责任。"}', 1, 70),
(8, 2, '违约责任与赔偿上限', '违约金比例、赔偿上限是否足以覆盖损失', '', '[{"name":"赔偿上限过低","highStd":"过低赔偿上限可能不足以覆盖实际损失。","lowStd":"违约责任条款需要与损失匹配。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"违约责任或赔偿上限过低，会削弱违约约束力。","suggestion":"提高违约金和赔偿上限，补充重大违约解除权。"}', 1, 80),
(9, 2, '合同解除与退出机制', '解除条件、退出与善后安排是否对等', '', '[{"name":"解除机制不对等","highStd":"解除条件不对等会影响我方退出权。","lowStd":"善后义务和费用结算需明确。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"合同解除和退出机制不够清晰，可能影响违约场景下的处置。","suggestion":"明确解除条件、通知期限、善后安排和费用结算。"}', 1, 90),
(10, 2, '法律适用与争议解决', '管辖、仲裁与法律适用是否对我方有利', '', '[{"name":"争议解决不利","highStd":"不利管辖会增加维权成本。","lowStd":"争议解决条款需要明确唯一方式。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"法律适用和争议解决约定不明确或不利。","suggestion":"明确适用法律、管辖法院或仲裁机构。"}', 1, 100),
(11, 3, '需求变更与费用调整', '变更流程与相应费用调整机制是否清晰', '', '[{"name":"变更费用风险","highStd":"需求变更无费用调整机制可能导致成本失控。","lowStd":"变更审批流程需细化。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"需求变更和费用调整机制不明确。","suggestion":"约定书面变更、审批流程、费用调整和工期顺延。"}', 1, 110),
(12, 4, '附件完整性与签章形式', '附件、签字盖章、份数与生效条件是否完整', '', '[{"name":"签章附件不完整","highStd":"附件或签章缺失可能影响文本完整性和效力。","lowStd":"份数和骑缝章要求需明确。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"附件和签章形式约定不完整。","suggestion":"补充附件清单、签章页、骑缝章和合同份数。"}', 1, 120),
(13, 3, '发票与费用承担', '税费、发票类型与开具时点约定是否明确', '', '[{"name":"发票税费风险","highStd":"发票类型或税费承担缺失会影响税务处理。","lowStd":"开票时点需与付款条件衔接。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"发票与税费承担约定不完整。","suggestion":"明确发票类型、税率、开具时点和税费承担。"}', 1, 130),
(14, 2, '不可抗力处理', '不可抗力情形、通知与责任免除是否合理', '', '[{"name":"不可抗力处理不清","highStd":"通知和减损义务缺失可能扩大争议。","lowStd":"不可抗力范围需与法律规定衔接。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"不可抗力处理流程不够完整。","suggestion":"明确不可抗力范围、通知期限、证明材料和减损义务。"}', 1, 140),
(15, 2, '转包与分包限制', '是否限制擅自转包、分包及相应责任', '', '[{"name":"转分包风险","highStd":"擅自转包分包会增加履约和合规风险。","lowStd":"第三方责任承担需明确。","noneStd":""}]', '[]', '{"level":"高风险","analysis":"转包与分包限制不明确。","suggestion":"禁止未经书面同意转包分包，并约定第三方责任。"}', 1, 150),
(16, 2, '保密期限与范围', '保密信息范围、期限与例外是否清晰', '', '[{"name":"保密范围不清","highStd":"保密范围和期限缺失可能导致商业秘密保护不足。","lowStd":"保密例外和披露流程需完善。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"保密期限与范围不够清晰。","suggestion":"明确保密信息范围、期限、例外情形和违约责任。"}', 1, 160),
(17, 3, '结算与对账方式', '结算周期、对账确认与争议处理是否明确', '', '[{"name":"结算对账风险","highStd":"对账确认机制缺失可能造成回款争议。","lowStd":"结算资料和争议处理需细化。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"结算与对账方式不明确。","suggestion":"明确结算周期、对账确认、异议期限和争议处理。"}', 1, 170),
(18, 4, '通知与送达条款', '通知方式、送达地址与生效时点是否完备', '', '[{"name":"送达条款风险","highStd":"通知送达不明会影响解除、索赔等权利行使。","lowStd":"送达地址和变更通知需明确。","noneStd":""}]', '[]', '{"level":"低风险","analysis":"通知与送达条款不够完备。","suggestion":"明确通知方式、送达地址、变更通知和生效时点。"}', 0, 180);
